import{_ as s,o as a,c as n,a2 as t}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Installing and Setup","description":"Getting Rust installed via rustup, configuring your editor, and verifying your development environment is ready.","frontmatter":{"title":"Installing and Setup","description":"Getting Rust installed via rustup, configuring your editor, and verifying your development environment is ready."},"headers":[],"relativePath":"learn/linear/02-rust-for-python-developers/02-installing-and-setup.md","filePath":"learn/linear/02-rust-for-python-developers/02-installing-and-setup.md"}'),o={name:"learn/linear/02-rust-for-python-developers/02-installing-and-setup.md"};function l(i,e,r,c,p,d){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="installing-and-setup" tabindex="-1">Installing and Setup <a class="header-anchor" href="#installing-and-setup" aria-label="Permalink to &quot;Installing and Setup&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to install Rust using rustup and manage toolchain versions</li><li>How to configure VS Code or your preferred editor with rust-analyzer for a productive workflow</li><li>How to verify your installation and troubleshoot common setup issues</li></ul></blockquote><p>Before you write a single line of Rust, you need a working development environment. If you have installed Python, you are used to downloading an installer or using pyenv to manage versions. Rust has its own version manager called <code>rustup</code>, and it is significantly simpler than the Python toolchain story.</p><h2 id="installing-rust-with-rustup" tabindex="-1">Installing Rust with rustup <a class="header-anchor" href="#installing-rust-with-rustup" aria-label="Permalink to &quot;Installing Rust with rustup&quot;">​</a></h2><p>Rust is installed through <code>rustup</code>, a command-line tool that manages Rust toolchain versions. Open your terminal and run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">curl</span><span style="color:#A6E3A1;"> --proto</span><span style="color:#A6E3A1;"> &#39;=https&#39;</span><span style="color:#A6E3A1;"> --tlsv1.2</span><span style="color:#A6E3A1;"> -sSf</span><span style="color:#A6E3A1;"> https://sh.rustup.rs</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> sh</span></span></code></pre></div><p>On Windows, download and run <code>rustup-init.exe</code> from <a href="https://rustup.rs" target="_blank" rel="noreferrer">rustup.rs</a>.</p><p>The installer will ask you to choose an installation option. Press <code>1</code> for the default installation. This installs three things:</p><ul><li><strong>rustc</strong> — the Rust compiler (analogous to the <code>python</code> interpreter)</li><li><strong>cargo</strong> — the build system and package manager (we will compare this to pip in the next section)</li><li><strong>rustup</strong> — the toolchain manager itself (analogous to pyenv)</li></ul><p>After installation, restart your terminal or run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;font-style:italic;">source</span><span style="color:#A6E3A1;"> &quot;</span><span style="color:#CDD6F4;">$HOME</span><span style="color:#A6E3A1;">/.cargo/env&quot;</span></span></code></pre></div><p>Verify the installation by checking versions:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustc</span><span style="color:#A6E3A1;"> --version</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># rustc 1.83.0 (90b35a623 2024-11-26)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> --version</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># cargo 1.83.0 (5ffbef321 2024-10-29)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> --version</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># rustup 1.27.1 (54dd3d00f 2024-04-24)</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, managing versions is a whole ordeal — pyenv, deadsnakes PPA, conda, the system Python you should never touch. Rust&#39;s <code>rustup</code> is like pyenv, virtualenv, and pip all rolled into one installer. There is exactly one blessed way to install Rust, and it works the same on every platform. No more &quot;which Python am I using?&quot; confusion.</p></div><h2 id="understanding-the-toolchain" tabindex="-1">Understanding the toolchain <a class="header-anchor" href="#understanding-the-toolchain" aria-label="Permalink to &quot;Understanding the toolchain&quot;">​</a></h2><p>A Rust &quot;toolchain&quot; is a specific version of the compiler plus its associated tools. By default, you are on the <code>stable</code> channel. Rust has three channels:</p><table tabindex="0"><thead><tr><th>Channel</th><th>Description</th><th>Python equivalent</th></tr></thead><tbody><tr><td><strong>stable</strong></td><td>Production-ready releases every 6 weeks</td><td>Latest stable Python release</td></tr><tr><td><strong>beta</strong></td><td>Next stable release, for testing</td><td>Python release candidates</td></tr><tr><td><strong>nightly</strong></td><td>Bleeding-edge, may contain unstable features</td><td>Python dev builds</td></tr></tbody></table><p>For this course, you will use <code>stable</code>. You can update to the latest stable release at any time:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> update</span><span style="color:#A6E3A1;"> stable</span></span></code></pre></div><p>To see which toolchains you have installed:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> toolchain</span><span style="color:#A6E3A1;"> list</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># stable-aarch64-apple-darwin (default)</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Unlike Python where version 3.11 and 3.12 can have meaningful behavioral differences, Rust&#39;s stability guarantee means that code that compiles on stable Rust 1.70 will compile on Rust 1.83 with the same behavior. Rust never breaks backward compatibility on the stable channel. This is a remarkable guarantee that the Python ecosystem does not offer.</p></div><h2 id="configuring-your-editor" tabindex="-1">Configuring your editor <a class="header-anchor" href="#configuring-your-editor" aria-label="Permalink to &quot;Configuring your editor&quot;">​</a></h2><p>The single most important thing you can do for Rust productivity is install <strong>rust-analyzer</strong>. It provides real-time feedback from the compiler as you type — autocompletion, type hints, error highlighting, and one-click fixes.</p><h3 id="vs-code-recommended-for-beginners" tabindex="-1">VS Code (recommended for beginners) <a class="header-anchor" href="#vs-code-recommended-for-beginners" aria-label="Permalink to &quot;VS Code (recommended for beginners)&quot;">​</a></h3><ol><li>Install the <a href="https://marketplace.visualstudio.com/items?itemName=rust-lang.rust-analyzer" target="_blank" rel="noreferrer">rust-analyzer extension</a></li><li>That is it. Seriously. Open a Rust project and it starts working.</li></ol><p>rust-analyzer gives you:</p><ul><li><strong>Inline type hints</strong> — hover over any variable to see its inferred type</li><li><strong>Error highlighting</strong> — red squiggles appear as you type, before you even save</li><li><strong>Go to definition</strong> — Ctrl/Cmd+click on any function, type, or module</li><li><strong>Code actions</strong> — automatic imports, derive macro additions, match arm generation</li><li><strong>Integrated terminal</strong> — run <code>cargo build</code> and <code>cargo test</code> without leaving the editor</li></ul><h3 id="other-editors" tabindex="-1">Other editors <a class="header-anchor" href="#other-editors" aria-label="Permalink to &quot;Other editors&quot;">​</a></h3><ul><li><strong>Neovim/Vim</strong> — use <code>nvim-lspconfig</code> with the <code>rust_analyzer</code> server</li><li><strong>Emacs</strong> — use <code>lsp-mode</code> or <code>eglot</code> with rust-analyzer</li><li><strong>IntelliJ/CLion</strong> — use the official Rust plugin (includes its own analysis engine)</li><li><strong>Zed</strong> — has built-in Rust support with rust-analyzer</li><li><strong>Helix</strong> — has built-in LSP support, just install rust-analyzer</li></ul><p>Whichever editor you choose, <strong>make sure rust-analyzer is working before you proceed</strong>. Open a Rust file, make a deliberate type error, and verify that it highlights the error. The quality of your learning experience depends heavily on this real-time feedback.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>If you use Pylance or Pyright in VS Code for Python, rust-analyzer provides a similar experience but with much deeper analysis. Because Rust&#39;s type system is richer and enforced by the compiler, rust-analyzer can give you more precise information. Where Pylance might say &quot;this could be <code>str | None</code>&quot;, rust-analyzer will tell you the exact type at every point in your code.</p></div><h2 id="useful-cargo-components" tabindex="-1">Useful Cargo components <a class="header-anchor" href="#useful-cargo-components" aria-label="Permalink to &quot;Useful Cargo components&quot;">​</a></h2><p>Install a couple of useful Cargo components that you will use throughout this course:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Clippy — a linter with hundreds of lint rules (think flake8/pylint for Rust)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> component</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> clippy</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Rustfmt — automatic code formatting (think black/ruff for Rust)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rustup</span><span style="color:#A6E3A1;"> component</span><span style="color:#A6E3A1;"> add</span><span style="color:#A6E3A1;"> rustfmt</span></span></code></pre></div><p>Now you can:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Format all code in a project (like running \`black .\`)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> fmt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Lint your code (like running \`flake8 .\` or \`ruff check .\`)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> clippy</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you choose and configure your own formatter (black, ruff, autopep8) and linter (flake8, pylint, ruff). In Rust, <code>rustfmt</code> and <code>clippy</code> are the official, community-standard tools. There is no debate about formatting style — <code>cargo fmt</code> produces the one true format, similar to how Go has <code>gofmt</code>. This means every Rust project you encounter will be formatted identically.</p></div><h2 id="verifying-everything-works" tabindex="-1">Verifying everything works <a class="header-anchor" href="#verifying-everything-works" aria-label="Permalink to &quot;Verifying everything works&quot;">​</a></h2><p>Let&#39;s verify your full setup with a quick test. Run these commands:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Create a new project</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> new</span><span style="color:#A6E3A1;"> hello-verify</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> hello-verify</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Build and run</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> run</span></span></code></pre></div><p>You should see:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>   Compiling hello-verify v0.1.0 (/path/to/hello-verify)</span></span>
<span class="line"><span>    Finished \`dev\` profile [unoptimized + debuginfo] target(s) in 0.50s</span></span>
<span class="line"><span>     Running \`target/debug/hello-verify\`</span></span>
<span class="line"><span>Hello, world!</span></span></code></pre></div><p>Now verify your tooling:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Format the code</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> fmt</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run the linter</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> clippy</span></span></code></pre></div><p>If all three commands succeed without errors, your environment is ready.</p><h2 id="troubleshooting-common-issues" tabindex="-1">Troubleshooting common issues <a class="header-anchor" href="#troubleshooting-common-issues" aria-label="Permalink to &quot;Troubleshooting common issues&quot;">​</a></h2><p><strong>&quot;command not found: cargo&quot;</strong> — Your shell configuration was not reloaded. Run <code>source &quot;$HOME/.cargo/env&quot;</code> or restart your terminal. On macOS/Linux, check that <code>$HOME/.cargo/bin</code> is in your <code>PATH</code>.</p><p><strong>&quot;linker &#39;cc&#39; not found&quot;</strong> — Rust needs a C linker to produce binaries. On macOS, install Xcode Command Line Tools with <code>xcode-select --install</code>. On Ubuntu/Debian, install <code>build-essential</code> with <code>sudo apt install build-essential</code>. On Fedora, <code>sudo dnf install gcc</code>.</p><p><strong>rust-analyzer not working</strong> — Make sure you opened a <em>folder</em> containing a <code>Cargo.toml</code> file, not just a loose <code>.rs</code> file. rust-analyzer needs the Cargo project structure to function.</p><p><strong>&quot;error: could not find <code>Cargo.toml</code>&quot;</strong> — You are running a Cargo command outside a Cargo project. Make sure you <code>cd</code> into a directory that contains a <code>Cargo.toml</code> file.</p><h2 id="clean-up" tabindex="-1">Clean up <a class="header-anchor" href="#clean-up" aria-label="Permalink to &quot;Clean up&quot;">​</a></h2><p>You can delete the test project now. We will create proper projects in the upcoming sections:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> ..</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">rm</span><span style="color:#A6E3A1;"> -rf</span><span style="color:#A6E3A1;"> hello-verify</span></span></code></pre></div><p>Your Rust development environment is ready. In the next section, you will learn how Cargo compares to the Python tools you already know.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Install Rust with <code>rustup</code>, which manages the compiler, Cargo, and toolchain versions in one tool — far simpler than Python&#39;s pyenv/pip/venv story</li><li>rust-analyzer is essential for a productive Rust experience — install it in your editor before writing any code</li><li><code>cargo fmt</code> and <code>cargo clippy</code> are the standard formatting and linting tools, equivalent to black and flake8 in the Python ecosystem</li><li>Rust&#39;s stability guarantee means code that compiles today will compile on future stable releases without breaking changes</li></ul>`,57)])])}const y=s(o,[["render",l]]);export{h as __pageData,y as default};
